        {
            <div class="text-danger small mt-1">@errorMessage</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }

        isSaving = true;
        errorMessage = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            // If the service doesn't assign the correct status, update it
            if (created.Status != DefaultStatus)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, DefaultStatus);
                created = created with { Status = DefaultStatus };
            }
            await OnTaskCreated.InvokeAsync(created);
            ResetForm();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task Cancel()
    {
        ResetForm();
        await OnCancel.InvokeAsync();
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
        errorMessage = null;
    }
}
"}

{"path": "/tmp/sv-ae567b7093694b4cab45a00fc75771bb/Components/Board/KanbanColumn.razor", "file_text": "<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          IsMoving="movingTaskId == task.Id"
                          OnMoveLeft="() => MoveLeft(task)"
                          OnMoveRight="() => MoveRight(task)" />
            }

            @if (showAddForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showAddForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100 mt-2" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(TaskItem Task, string Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task MoveLeft(TaskItem task)
    {
        movingTaskId = task.Id;
        await OnMoveTask.InvokeAsync((task, "left"));
        movingTaskId = null;
    }

    private async Task MoveRight(TaskItem task)
    {
        movingTaskId = task.Id;
        await OnMoveTask.InvokeAsync((task, "right"));
        movingTaskId = null;
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}
"}

