@page "/board"
@rendermode InteractiveServer
@using sv_ae567b7093694b4cab45a00fc75771bb.Components.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   TodoCount="todoTasks.Count"
                   InProgressCount="inProgressTasks.Count"
                   DoneCount="doneTasks.Count"
                   OverdueCount="overdueTasks.Count" />

    <BoardSearchBar SearchText="@searchText" SearchTextChanged="OnSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="filteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="filteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="Done"
                      Tasks="filteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Columns = { "To Do", "In Progress", "Done" };

    // Unfiltered column lists (for stats)
    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate < DateTime.Today).ToList();

    // Filtered column lists (for display)
    private List<TaskItem> filteredTodo => ApplyFilter(todoTasks);
    private List<TaskItem> filteredInProgress => ApplyFilter(inProgressTasks);
    private List<TaskItem> filteredDone => ApplyFilter(doneTasks);

    private List<TaskItem> ApplyFilter(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void OnSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task HandleMoveTask((TaskItem Task, string Direction) move)
    {
        var currentIndex = Array.IndexOf(Columns, move.Task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Columns.Length) return;

        var newStatus = Columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.Task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == move.Task.Id);
            if (index >= 0)
            {
                allTasks[index] = move.Task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}

